parameters.text:
=Extract quote data from this email:

Subject: {{ $('Gmail Trigger').item.json.subject }}

Body: {{ $json.textPlain || $json.textHtml }}

Attachments:{{ $json.text }}

textOptions.schema:
{
  "type": "object",
  "properties": {
    "case_id": {
      "type": "string"
    },
    "is_submission_complete": {
      "type": "boolean"
    },
    "quotes_received_count": {
      "type": "integer"
    },
    "min_quotes_required": {
      "type": "integer"
    },
    "recommended_supplier_name": {
      "type": ["string", "null"]
    },
    "recommended_total_price_eur": {
      "type": "number"
    },
    "recommendation_reason": {
      "type": "string",
      "description": "A detailed analysis justifying the recommendation based on scores."
    },
    "scorecard": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "supplier_name": {
            "type": "string"
          },
          "total_price_eur": {
            "type": "number"
          },
          "price_rank": {
            "type": "integer"
          },
          "compliance_status": {
            "type": "string"
          },
          "disqualification_reasons": {
            "type": "array",
            "items": {
              "type": "string"
            }
          },
          "score": {
            "type": "integer"
          }
        },
        "required": [
          "supplier_name",
          "total_price_eur",
          "price_rank",
          "compliance_status",
          "disqualification_reasons",
          "score"
        ],
        "additionalProperties": false
      }
    }
  },
  "additionalProperties": false,
  "required": [
    "case_id",
    "is_submission_complete",
    "quotes_received_count",
    "min_quotes_required",
    "recommended_supplier_name",
    "recommended_total_price_eur",
    "recommendation_reason",
    "scorecard"
  ]
}
